pause(2);
    blodia1.freeze(2);
    wallsection001.crumble(x=4, y=0)
    wallsection002.crumble(x=4, y=0)

script.playerTouches:
for (spell in shuffle(["fireball", "freeze", "vanish", "speed", "omnivision", "spikes", "maze", "teleport", "shield"])) {
      if (!player.hasMagic(spell)) {
         unlockMagic(spell);
         scrollMessage(
            "Your powers as a wizard increased! You have unlocked: {spell}!",
            image(magicIcon(spell))
         );
         break;
      }
   };
